const e=JSON.parse('{"key":"v-eb8da3b0","path":"/Front/Vue/advanced/Vuescoped.html","title":"Vue中scoped和scoped穿透","lang":"zh-CN","frontmatter":{"description":"Vue中scoped和scoped穿透 什么是scoped？ 在Vue文件中的style标签上有一个特殊的属性scoped。当一个style标签拥有scoped属性时候，它的css样式只能用于当前的Vue组件，可以使组件的样式不相互污染。如果一个项目的所有style标签都加上了scoped属性，相当于实现了样式的模块化。","head":[["meta",{"property":"og:url","content":"https://lfange.github.io/Front/Vue/advanced/Vuescoped.html"}],["meta",{"property":"og:site_name","content":"哓番茄"}],["meta",{"property":"og:title","content":"Vue中scoped和scoped穿透"}],["meta",{"property":"og:description","content":"Vue中scoped和scoped穿透 什么是scoped？ 在Vue文件中的style标签上有一个特殊的属性scoped。当一个style标签拥有scoped属性时候，它的css样式只能用于当前的Vue组件，可以使组件的样式不相互污染。如果一个项目的所有style标签都加上了scoped属性，相当于实现了样式的模块化。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2022-08-23T09:28:43.000Z"}],["meta",{"property":"article:author","content":"哓番茄"}],["meta",{"property":"article:modified_time","content":"2022-08-23T09:28:43.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Vue中scoped和scoped穿透\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2022-08-23T09:28:43.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"哓番茄\\",\\"url\\":\\"https://lfange.github.io/\\"}]}"],["link",{"rel":"alternate","type":"application/atom+xml","href":"https://lfange.github.io/atom.xml","title":"哓番茄 Atom Feed"}],["link",{"rel":"alternate","type":"application/json","href":"https://lfange.github.io/feed.json","title":"哓番茄 JSON Feed"}],["link",{"rel":"alternate","type":"application/rss+xml","href":"https://lfange.github.io/rss.xml","title":"哓番茄 RSS Feed"}]]},"headers":[{"level":2,"title":"什么是scoped？","slug":"什么是scoped","link":"#什么是scoped","children":[]},{"level":2,"title":"scoped的实现原理","slug":"scoped的实现原理","link":"#scoped的实现原理","children":[]},{"level":2,"title":"scoped穿透","slug":"scoped穿透","link":"#scoped穿透","children":[]},{"level":2,"title":"在组件中修改第三方组件库样式的其它方法","slug":"在组件中修改第三方组件库样式的其它方法","link":"#在组件中修改第三方组件库样式的其它方法","children":[]}],"git":{"createdTime":1661246923000,"updatedTime":1661246923000,"contributors":[{"name":"FanGe","email":"653398363@qq.com","commits":1}]},"readingTime":{"minutes":2.26,"words":677},"filePathRelative":"Front/Vue/advanced/Vuescoped.md","localizedDate":"2022年8月23日","excerpt":"<h1> Vue中scoped和scoped穿透</h1>\\n<h2> 什么是scoped？</h2>\\n<p>在Vue文件中的style标签上有一个特殊的属性<code>scoped</code>。当一个style标签拥有<code>scoped</code>属性时候，它的css样式只能用于当前的Vue组件，可以使组件的样式不相互污染。如果一个项目的所有style标签都加上了<code>scoped</code>属性，相当于实现了样式的模块化。</p>\\n","autoDesc":true}');export{e as data};
